        switch laError.code {
        case .biometryNotAvailable:
            return "Biometric authentication is not available on this device."
        case .biometryNotEnrolled:
            return biometricType == .faceID
                ? "Face ID is not set up. You can enter your password instead."
                : "Touch ID is not set up. You can enter your password instead."
        case .biometryLockout:
            return "Biometrics are locked due to too many failed attempts. Please enter your password."
        default:
