            return "Authentication failed. Please try again or enter your password."
        case .userCancel:
            return "Authentication was canceled. You can try again or enter your password."
        case .userFallback:
            return "Please enter your password to continue."
        case .systemCancel:
            return "Authentication was interrupted. Please try again."
        case .biometryLockout:
            return "Biometrics are locked due to too many failed attempts. Please enter your password."
        case .biometryNotAvailable:
            return "Biometric authentication is not available. Please enter your password."
        case .biometryNotEnrolled:
            return biometricType == .faceID
